import{_ as t,c as i,o as a,ax as o}from"./chunks/framework.DHqKNX4U.js";const u=JSON.parse('{"title":"Retention Policy","description":"","frontmatter":{},"headers":[],"relativePath":"enterprise/retention-policy/index.md","filePath":"enterprise/retention-policy/index.md"}'),r={name:"enterprise/retention-policy/index.md"};function n(s,e,l,d,c,h){return a(),i("div",null,e[0]||(e[0]=[o('<h1 id="retention-policy" tabindex="-1">Retention Policy <a class="header-anchor" href="#retention-policy" aria-label="Permalink to &quot;Retention Policy&quot;">​</a></h1><p>The Retention Policy Engine is an enterprise-grade feature that automates the lifecycle management of archived emails. It enables organizations to define time-based retention rules that determine how long archived emails are kept before they are permanently deleted, ensuring compliance with data protection regulations and internal data governance policies.</p><h2 id="core-principles" tabindex="-1">Core Principles <a class="header-anchor" href="#core-principles" aria-label="Permalink to &quot;Core Principles&quot;">​</a></h2><h3 id="_1-policy-based-automation" tabindex="-1">1. Policy-Based Automation <a class="header-anchor" href="#_1-policy-based-automation" aria-label="Permalink to &quot;1. Policy-Based Automation&quot;">​</a></h3><p>Email deletion is never arbitrary. Every deletion is governed by one or more explicitly configured retention policies that define the retention period in days, the conditions under which the policy applies, and the action to take when an email expires. The lifecycle worker processes emails in batches on a recurring schedule, ensuring continuous enforcement without manual intervention.</p><h3 id="_2-condition-based-targeting" tabindex="-1">2. Condition-Based Targeting <a class="header-anchor" href="#_2-condition-based-targeting" aria-label="Permalink to &quot;2. Condition-Based Targeting&quot;">​</a></h3><p>Policies can target specific subsets of archived emails using a flexible condition builder. Conditions are evaluated against email metadata fields (sender, recipient, subject, attachment type) using a variety of string-matching operators. Conditions within a policy are grouped using AND/OR logic, allowing precise control over which emails a policy applies to.</p><h3 id="_3-ingestion-scope" tabindex="-1">3. Ingestion Scope <a class="header-anchor" href="#_3-ingestion-scope" aria-label="Permalink to &quot;3. Ingestion Scope&quot;">​</a></h3><p>Each policy can optionally be scoped to one or more ingestion sources. When an ingestion scope is set, the policy only applies to emails that were archived from those specific sources. Policies with no ingestion scope (null) apply to all emails regardless of their source.</p><h3 id="_4-priority-and-max-duration-wins" tabindex="-1">4. Priority and Max-Duration-Wins <a class="header-anchor" href="#_4-priority-and-max-duration-wins" aria-label="Permalink to &quot;4. Priority and Max-Duration-Wins&quot;">​</a></h3><p>When multiple policies match a single email, the system applies <strong>max-duration-wins</strong> logic: the longest matching retention period is used. This ensures that if any policy requires an email to be kept longer, that requirement is honored. The priority field on each policy provides an ordering mechanism for administrative purposes and future conflict-resolution enhancements.</p><h3 id="_5-full-audit-trail" tabindex="-1">5. Full Audit Trail <a class="header-anchor" href="#_5-full-audit-trail" aria-label="Permalink to &quot;5. Full Audit Trail&quot;">​</a></h3><p>Every policy lifecycle event — creation, modification, deletion, and every automated email deletion — is recorded in the immutable <a href="./../audit-log/">Audit Log</a>. Automated deletions include the IDs of the governing policies in the audit log entry, ensuring full traceability from deletion back to the rule that triggered it.</p><h3 id="_6-fail-safe-behavior" tabindex="-1">6. Fail-Safe Behavior <a class="header-anchor" href="#_6-fail-safe-behavior" aria-label="Permalink to &quot;6. Fail-Safe Behavior&quot;">​</a></h3><p>The system is designed to err on the side of caution:</p><ul><li>If no policy matches an email, the email is <strong>not</strong> deleted.</li><li>If the lifecycle worker encounters an error processing a specific email, it logs the error and continues with the remaining emails in the batch.</li><li>Invalid regex patterns in <code>regex_match</code> rules are treated as non-matching rather than causing failures.</li></ul><h2 id="feature-requirements" tabindex="-1">Feature Requirements <a class="header-anchor" href="#feature-requirements" aria-label="Permalink to &quot;Feature Requirements&quot;">​</a></h2><p>The Retention Policy Engine requires:</p><ul><li>An active <strong>Enterprise license</strong> with the <code>RETENTION_POLICY</code> feature enabled.</li><li>The <code>manage:all</code> permission for the authenticated user to access the policy management API and UI.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The feature is composed of the following components:</p><table tabindex="0"><thead><tr><th>Component</th><th>Location</th><th>Description</th></tr></thead><tbody><tr><td>Types</td><td><code>packages/types/src/retention.types.ts</code></td><td>Shared TypeScript types for policies, rules, and evaluation.</td></tr><tr><td>Database Schema</td><td><code>packages/backend/src/database/schema/compliance.ts</code></td><td>Drizzle ORM table definition for <code>retention_policies</code>.</td></tr><tr><td>Retention Service</td><td><code>packages/enterprise/src/modules/retention-policy/RetentionService.ts</code></td><td>CRUD operations and the evaluation engine.</td></tr><tr><td>API Controller</td><td><code>packages/enterprise/src/modules/retention-policy/retention-policy.controller.ts</code></td><td>Express request handlers with Zod validation.</td></tr><tr><td>API Routes</td><td><code>packages/enterprise/src/modules/retention-policy/retention-policy.routes.ts</code></td><td>Route registration with auth and feature guards.</td></tr><tr><td>Module</td><td><code>packages/enterprise/src/modules/retention-policy/retention-policy.module.ts</code></td><td>Enterprise module bootstrap.</td></tr><tr><td>Lifecycle Worker</td><td><code>packages/enterprise/src/workers/lifecycle.worker.ts</code></td><td>BullMQ worker for automated retention enforcement.</td></tr><tr><td>Frontend Page</td><td><code>packages/frontend/src/routes/dashboard/compliance/retention-policies/</code></td><td>SvelteKit page for policy management and simulation.</td></tr></tbody></table>',22)]))}const m=t(r,[["render",n]]);export{u as __pageData,m as default};
